<template>
  <div class="booking-page">
    <section class="booking-toolbar">
      <div class="toolbar-title">
        <h2>课程预约</h2>
        <p>浏览课程、咨询教师或提交预约申请</p>
      </div>
      <el-form :inline="true" :model="query" size="small" class="toolbar-form">
        <el-form-item label="课程名">
          <el-input v-model="query.name" placeholder="搜索课程" clearable prefix-icon="el-icon-search" />
        </el-form-item>
        <el-form-item>
          <el-button type="primary" icon="el-icon-search" @click="loadCourses">搜索</el-button>
        </el-form-item>
      </el-form>
    </section>

    <el-row :gutter="20" class="course-grid">
      <el-col v-for="c in courses" :key="c.id" :xs="24" :sm="12" :md="8" :lg="6">
        <article class="course-card" @click="goDetail(c)">
          <div class="course-card-cover">
            <img v-if="c.coverImage" :src="c.coverImage" alt="">
            <div v-else class="course-card-cover--empty"><i class="el-icon-headset" /></div>
            <span class="course-card-price">¥{{ c.price }}</span>
          </div>
          <div class="course-card-body">
            <h3 class="course-card-title">{{ c.name }}</h3>
            <div class="course-card-teacher">
              <i class="el-icon-user-solid" />
              <span class="course-card-teacher-name">{{ c.teacherName || '待定' }}</span>
            </div>
            <div class="course-card-meta">
              <span><i class="el-icon-time" /> {{ c.duration }} 分钟/节</span>
            </div>
            <div class="course-card-actions" @click.stop>
              <el-button size="small" class="btn-consult" icon="el-icon-chat-dot-round" @click="openConsult(c)">咨询</el-button>
              <el-button type="primary" size="small" icon="el-icon-date" @click="openBooking(c)">预约</el-button>
            </div>
          </div>
        </article>
      </el-col>
    </el-row>

    <el-card class="my-bookings-card" shadow="never">
      <div slot="header" class="my-bookings-header">我的预约</div>
      <el-table :data="myBookings" border stripe>
        <el-table-column prop="courseName" label="课程" min-width="120" />
        <el-table-column prop="teacherName" label="教师" width="100" />
        <el-table-column prop="bookingTime" label="预约时间" width="170" />
        <el-table-column prop="status" label="状态" width="90">
          <template slot-scope="scope">
            <el-tag :type="scope.row.status===1?'success':scope.row.status===2?'danger':'warning'" size="small">
              {{ scope.row.status===0?'待审批':scope.row.status===1?'已通过':'已拒绝' }}
            </el-tag>
          </template>
        </el-table-column>
      </el-table>
    </el-card>

    <el-dialog title="预约课程" :visible.sync="dialogVisible" width="500px" append-to-body>
      <el-form :model="form" label-width="100px">
        <el-form-item label="课程"><el-input :value="selectedCourse.name" disabled /></el-form-item>
        <el-form-item label="教师"><el-input :value="selectedCourse.teacherName" disabled /></el-form-item>
        <el-form-item label="预约时间">
          <el-date-picker v-model="form.bookingTime" type="datetime" value-format="yyyy-MM-dd HH:mm:ss" placeholder="选择时间" style="width:100%" />
        </el-form-item>
        <el-form-item label="备注"><el-input v-model="form.remark" type="textarea" /></el-form-item>
      </el-form>
      <span slot="footer">
        <el-button @click="dialogVisible=false">取消</el-button>
        <el-button type="primary" @click="submitBooking">确认预约</el-button>
      </span>
    </el-dialog>

    <consult-teacher-dialog :visible.sync="consultVisible" :course="consultCourse" />
  </div>
</template>

<script>
import request from '@/utils/request'
import ConsultTeacherDialog from '@/components/ConsultTeacherDialog.vue'

export default {
  components: { ConsultTeacherDialog },
  data() {
    return {
      courses: [],
      myBookings: [],
      dialogVisible: false,
      consultVisible: false,
      consultCourse: {},
      query: { name: '' },
      selectedCourse: {},
      form: {}
    }
  },
  created() {
    this.loadCourses()
    this.loadMyBookings()
  },
  methods: {
    loadCourses() {
      request.get('/api/course', { params: { pageNum: 1, pageSize: 999, status: 1, ...this.query } }).then(res => {
        this.courses = res.data.records || []
      }).catch(() => {})
    },
    loadMyBookings() {
      const user = JSON.parse(sessionStorage.getItem('loginUser') || '{}')
      request.get('/api/booking', { params: { pageNum: 1, pageSize: 999, studentId: user.id } }).then(res => {
        this.myBookings = res.data.records || []
      }).catch(() => {})
    },
    goDetail(c) {
      this.$router.push(`/student/course/${c.id}`)
    },
    openConsult(c) {
      this.consultCourse = { ...c }
      this.consultVisible = true
    },
    openBooking(course) {
      this.selectedCourse = course
      const user = JSON.parse(sessionStorage.getItem('loginUser') || '{}')
      this.form = { courseId: course.id, studentId: user.id, teacherId: course.teacherId, status: 0 }
      this.dialogVisible = true
    },
    submitBooking() {
      if (!this.form.bookingTime) {
        this.$message.warning('请选择预约时间')
        return
      }
      request.post('/api/booking', this.form).then(() => {
        this.$message.success('预约成功，等待教师审批')
        this.dialogVisible = false
        this.loadMyBookings()
      }).catch(() => {})
    }
  }
}
</script>

<style scoped>
.booking-page {
  max-width: 1200px;
  margin: 0 auto;
}

.booking-toolbar {
  display: flex;
  flex-wrap: wrap;
  align-items: flex-end;
  justify-content: space-between;
  gap: 16px;
  margin-bottom: 24px;
  padding: 20px 22px;
  background: #fff;
  border-radius: 16px;
  border: 1px solid #eef0f4;
  box-shadow: 0 4px 20px rgba(15, 23, 42, 0.05);
}

.toolbar-title h2 {
  margin: 0 0 6px;
  font-size: 20px;
  font-weight: 700;
  color: #1a1d26;
}

.toolbar-title p {
  margin: 0;
  font-size: 13px;
  color: #909399;
}

.toolbar-form >>> .el-input__inner {
  border-radius: 10px;
}

.course-grid {
  margin-bottom: 8px;
}

.course-card {
  background: #fff;
  border-radius: 16px;
  overflow: hidden;
  border: 1px solid #eceef3;
  box-shadow: 0 4px 18px rgba(15, 23, 42, 0.06);
  margin-bottom: 20px;
  cursor: pointer;
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.course-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 28px rgba(108, 92, 231, 0.15);
}

.course-card-cover {
  position: relative;
  height: 140px;
  background: linear-gradient(145deg, #eef0fb, #e4e7f5);
}

.course-card-cover img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.course-card-cover--empty {
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 48px;
  color: #c8cce0;
}

.course-card-price {
  position: absolute;
  right: 10px;
  bottom: 10px;
  padding: 4px 10px;
  border-radius: 20px;
  font-size: 13px;
  font-weight: 600;
  color: #fff;
  background: rgba(26, 29, 38, 0.72);
  backdrop-filter: blur(4px);
}

.course-card-body {
  padding: 14px 14px 16px;
}

.course-card-title {
  margin: 0 0 10px;
  font-size: 15px;
  font-weight: 600;
  color: #303133;
  line-height: 1.35;
  min-height: 40px;
}

.course-card-teacher {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 14px;
  color: #6c5ce7;
  font-weight: 600;
  margin-bottom: 8px;
}

.course-card-teacher i {
  font-size: 15px;
}

.course-card-teacher-name {
  flex: 1;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.course-card-meta {
  font-size: 12px;
  color: #909399;
  margin-bottom: 12px;
}

.course-card-meta i {
  margin-right: 4px;
}

.course-card-actions {
  display: flex;
  flex-wrap: nowrap;
  gap: 8px;
}

.course-card-actions >>> .el-button {
  flex: 1;
  min-width: 0;
  border-radius: 10px;
  margin: 0;
}

.btn-consult {
  border-color: #dcdfe6;
  color: #606266;
}

.btn-consult:hover {
  border-color: #6c5ce7;
  color: #6c5ce7;
  background: rgba(108, 92, 231, 0.06);
}

.my-bookings-card {
  margin-top: 8px;
  border-radius: 16px;
  border: 1px solid #eef0f4;
}

.my-bookings-header {
  font-weight: 600;
  font-size: 15px;
}
</style>
